const pptxgen = require("pptxgenjs");

const pres = new pptxgen();
pres.layout = 'LAYOUT_4x3'; // 10" × 7.5"
pres.title = 'Ciberseguridad en Redes Eléctricas Inteligentes';
pres.author = '[REDACTED_INFRASTRUCTURE]';

// ── Palette ─────────────────────────────────────────────────
const C = {
  darkBg:    '0A1628',   // deep navy
  midBg:     '112240',   // section headers
  cardBg:    '152A4E',   // card backgrounds
  accentBlue:'0077B6',   // primary accent
  accentCyan:'00B4D8',   // secondary
  accentMint:'06D6A0',   // highlight / success
  accentAmber:'FFB703',  // warning highlight
  white:     'FFFFFF',
  offWhite:  'E8F4F8',
  lightGray: 'A8C5DA',
  lightBg:   'F0F6FC',   // light content slides
  darkText:  '0A1628',
  bodyText:  '1E3A5F',
};

const FONT_H = 'Trebuchet MS';
const FONT_B = 'Calibri';

// ── Helpers ──────────────────────────────────────────────────
function darkSlide(slide) {
  slide.background = { color: C.darkBg };
}
function lightSlide(slide) {
  slide.background = { color: C.lightBg };
}

// Left accent bar
function accentBar(slide, color = C.accentCyan, h = 0.08, y = 0) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: y, w: 10, h: h,
    fill: { color }, line: { color, width: 0 }
  });
}
function accentBarV(slide, color = C.accentBlue, w = 0.07, x = 0.5, y = 1.1, h = 0.5) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x, y, w, h,
    fill: { color }, line: { color, width: 0 }
  });
}

function sectionTag(slide, text, x = 0.5, y = 0.15, color = C.accentMint) {
  slide.addShape(pres.shapes.ROUNDED_RECTANGLE, {
    x, y, w: text.length * 0.13 + 0.3, h: 0.28,
    fill: { color, transparency: 20 },
    line: { color, width: 0 },
    rectRadius: 0.05
  });
  slide.addText(text, {
    x, y, w: text.length * 0.13 + 0.3, h: 0.28,
    fontSize: 9, fontFace: FONT_B, color: C.darkBg,
    bold: true, align: 'center', valign: 'middle', margin: 0
  });
}

function darkTitle(slide, text, y = 0.55, color = C.white) {
  slide.addText(text, {
    x: 0.5, y, w: 9, h: 0.65,
    fontSize: 26, fontFace: FONT_H, color,
    bold: true, align: 'left', valign: 'middle', margin: 0
  });
}

function lightTitle(slide, text, y = 0.5) {
  slide.addText(text, {
    x: 0.5, y, w: 9, h: 0.65,
    fontSize: 24, fontFace: FONT_H, color: C.darkText,
    bold: true, align: 'left', valign: 'middle', margin: 0
  });
}

function darkCard(slide, x, y, w, h, color = C.cardBg) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x, y, w, h,
    fill: { color },
    line: { color: C.accentCyan, width: 0.5, transparency: 70 },
    shadow: { type: 'outer', color: '000000', blur: 8, offset: 2, angle: 135, opacity: 0.3 }
  });
}

function lightCard(slide, x, y, w, h) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x, y, w, h,
    fill: { color: C.white },
    line: { color: C.accentBlue, width: 0.5, transparency: 60 },
    shadow: { type: 'outer', color: '000000', blur: 6, offset: 1, angle: 135, opacity: 0.1 }
  });
}

function footerDark(slide) {
  slide.addText('[REDACTED_INFRASTRUCTURE]  ·  Once B  ·  2026', {
    x: 0.5, y: 7.25, w: 9, h: 0.2,
    fontSize: 7, fontFace: FONT_B, color: C.lightGray, align: 'center', margin: 0
  });
}
function footerLight(slide) {
  slide.addText('[REDACTED_INFRASTRUCTURE]  ·  Once B  ·  2026', {
    x: 0.5, y: 7.25, w: 9, h: 0.2,
    fontSize: 7, fontFace: FONT_B, color: C.bodyText, opacity: 0.5, align: 'center', margin: 0
  });
}

// ── SLIDE 1: COVER ───────────────────────────────────────────
{
  const sl = pres.addSlide();
  darkSlide(sl);
  // Decorative grid lines
  for (let i = 0; i < 6; i++) {
    sl.addShape(pres.shapes.LINE, {
      x: i * 2, y: 0, w: 0, h: 7.5,
      line: { color: C.accentBlue, width: 0.3, transparency: 80 }
    });
  }
  // Top accent
  sl.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 10, h: 0.12,
    fill: { color: C.accentCyan }, line: { color: C.accentCyan, width: 0 }
  });
  sl.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0.12, w: 10, h: 0.06,
    fill: { color: C.accentMint }, line: { color: C.accentMint, width: 0 }
  });

  // Main title
  sl.addText('Ciberseguridad en', {
    x: 0.6, y: 1.5, w: 8.8, h: 0.9,
    fontSize: 38, fontFace: FONT_H, color: C.offWhite, bold: true, margin: 0
  });
  sl.addText('Redes Eléctricas Inteligentes', {
    x: 0.6, y: 2.35, w: 8.8, h: 0.9,
    fontSize: 38, fontFace: FONT_H, color: C.accentCyan, bold: true, margin: 0
  });

  // Subtitle
  sl.addShape(pres.shapes.RECTANGLE, {
    x: 0.6, y: 3.35, w: 8.8, h: 0.04,
    fill: { color: C.accentMint, transparency: 40 }, line: { color: C.accentMint, width: 0 }
  });
  sl.addText('Amenazas, Defensas e Implementación Estratégica', {
    x: 0.6, y: 3.45, w: 8.8, h: 0.45,
    fontSize: 16, fontFace: FONT_B, color: C.lightGray, italic: true, margin: 0
  });

  // Info block
  sl.addShape(pres.shapes.RECTANGLE, {
    x: 0.6, y: 4.2, w: 8.8, h: 1.5,
    fill: { color: C.cardBg }, line: { color: C.accentBlue, width: 0.5, transparency: 50 }
  });
  sl.addText([
    { text: 'Autores del artículo: ', options: { color: C.lightGray, fontSize: 12, fontFace: FONT_B } },
    { text: 'Ali, Wadi & Elmasry', options: { color: C.accentCyan, fontSize: 12, fontFace: FONT_B, bold: true } },
    { text: '\n', options: { breakLine: true } },
    { text: 'Presentado por: ', options: { color: C.lightGray, fontSize: 12, fontFace: FONT_B } },
    { text: '[REDACTED_INFRASTRUCTURE]', options: { color: C.white, fontSize: 12, fontFace: FONT_B, bold: true } },
    { text: '\n', options: { breakLine: true } },
    { text: '[REDACTED_INFRASTRUCTURE]: ', options: { color: C.lightGray, fontSize: 12, fontFace: FONT_B } },
    { text: 'Once B', options: { color: C.white, fontSize: 12, fontFace: FONT_B, bold: true } },
    { text: '        [REDACTED_INFRASTRUCTURE]: ', options: { color: C.lightGray, fontSize: 12, fontFace: FONT_B } },
    { text: '2026', options: { color: C.accentMint, fontSize: 12, fontFace: FONT_B, bold: true } },
  ], { x: 0.9, y: 4.35, w: 8.2, h: 1.2, margin: 5 });

  // Bottom bar
  sl.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 7.38, w: 10, h: 0.12,
    fill: { color: C.accentBlue }, line: { color: C.accentBlue, width: 0 }
  });
}

// ── SLIDE 2: ÍNDICE ──────────────────────────────────────────
{
  const sl = pres.addSlide();
  lightSlide(sl);
  accentBar(sl, C.accentBlue, 0.1, 0);
  lightTitle(sl, 'Índice de Contenidos', 0.3);

  const left = [
    ['01', 'Introducción: Amenaza Teórica → Realidad'],
    ['02', 'Metodología: Revisión PRISMA'],
    ['03', 'Taxonomía de Amenazas'],
    ['04', 'Autenticación y Privacidad'],
    ['05', 'Protocolos de Comunicación'],
    ['06', 'Machine Learning: Modelos'],
    ['07', 'ML: Limitaciones Estructurales'],
    ['08', 'Marcos Teóricos de Defensa'],
    ['09', 'Vectores Emergentes: EV y DER'],
    ['10', 'Discusión: Brechas de Investigación'],
    ['11', 'Conclusiones: Arquitectura Sistémica'],
  ];
  const right = [
    ['12', 'Conclusiones: La [REDACTED_INFRASTRUCTURE] como Bastión'],
    ['13', 'IA Generativa y Nuevas Amenazas'],
    ['14', 'Disciplina de Frontera Interdisciplinaria'],
    ['15', 'Factor Humano: Regla y Excepción'],
    ['16', 'Glosario Técnico – Parte 1'],
    ['17', 'Glosario Técnico – Parte 2'],
    ['18', 'Palabras Clave'],
    ['19', 'Referencias Bibliográficas'],
  ];

  left.forEach(([num, label], i) => {
    const y = 1.15 + i * 0.54;
    lightCard(sl, 0.4, y, 4.4, 0.46);
    sl.addShape(pres.shapes.RECTANGLE, { x: 0.4, y, w: 0.4, h: 0.46, fill: { color: C.accentBlue }, line: { color: C.accentBlue, width: 0 } });
    sl.addText(num, { x: 0.4, y, w: 0.4, h: 0.46, fontSize: 11, fontFace: FONT_H, color: C.white, bold: true, align: 'center', valign: 'middle', margin: 0 });
    sl.addText(label, { x: 0.85, y: y + 0.05, w: 3.85, h: 0.36, fontSize: 10, fontFace: FONT_B, color: C.darkText, valign: 'middle', margin: 0 });
  });

  right.forEach(([num, label], i) => {
    const y = 1.15 + i * 0.7;
    lightCard(sl, 5.15, y, 4.4, 0.62);
    sl.addShape(pres.shapes.RECTANGLE, { x: 5.15, y, w: 0.4, h: 0.62, fill: { color: C.accentMint }, line: { color: C.accentMint, width: 0 } });
    sl.addText(num, { x: 5.15, y, w: 0.4, h: 0.62, fontSize: 11, fontFace: FONT_H, color: C.darkText, bold: true, align: 'center', valign: 'middle', margin: 0 });
    sl.addText(label, { x: 5.6, y: y + 0.07, w: 3.85, h: 0.48, fontSize: 10, fontFace: FONT_B, color: C.darkText, valign: 'middle', margin: 0 });
  });
  footerLight(sl);
}

// ── SLIDE 3: INTRODUCCIÓN ────────────────────────────────────
{
  const sl = pres.addSlide();
  darkSlide(sl);
  sectionTag(sl, 'INTRODUCCIÓN');
  darkTitle(sl, 'De la Amenaza Teórica a la Realidad Operativa', 0.5);
  accentBar(sl, C.accentCyan, 0.05, 1.25);

  // Casos documentados
  darkCard(sl, 0.4, 1.4, 4.5, 3.8);
  sl.addText('CASOS DOCUMENTADOS', {
    x: 0.55, y: 1.52, w: 4.2, h: 0.35,
    fontSize: 11, fontFace: FONT_H, color: C.accentCyan, bold: true, margin: 0
  });
  const casos = [
    ['🌐 Apagón Ucrania (2015)', '230.000 usuarios afectados'],
    ['⚡ Industroyer2 (2022)', 'Malware para relés IEC 104'],
    ['💻 BlackCat/Ørsted (2023)', 'Ransomware contra energía'],
  ];
  casos.forEach(([title, desc], i) => {
    const y = 1.95 + i * 0.95;
    sl.addShape(pres.shapes.RECTANGLE, { x: 0.55, y, w: 4.2, h: 0.82,
      fill: { color: C.midBg }, line: { color: C.accentBlue, width: 0.3, transparency: 50 } });
    sl.addText(title, { x: 0.65, y: y + 0.06, w: 4.0, h: 0.28, fontSize: 11, fontFace: FONT_H, color: C.white, bold: true, margin: 0 });
    sl.addText(desc, { x: 0.65, y: y + 0.37, w: 4.0, h: 0.28, fontSize: 10, fontFace: FONT_B, color: C.lightGray, margin: 0 });
  });

  // Reencuadre del problema
  darkCard(sl, 5.15, 1.4, 4.45, 3.8);
  sl.addText('REENCUADRE DEL PROBLEMA', {
    x: 5.3, y: 1.52, w: 4.15, h: 0.35,
    fontSize: 11, fontFace: FONT_H, color: C.accentMint, bold: true, margin: 0
  });
  const items = [
    'No es un problema informático convencional',
    'Es un problema CIBERFÍSIC[LOCAL_PATH] datos digitales → efectos físicos',
    'Apagones, daño a transformadores,\n inestabilidad de frecuencia',
    'Requiere enfoque integrad[LOCAL_PATH] ingeniería eléctrica + ciberseguridad',
  ];
  items.forEach((text, i) => {
    sl.addShape(pres.shapes.RECTANGLE, { x: 5.3, y: 1.95 + i * 0.76, w: 0.07, h: 0.55, fill: { color: C.accentMint }, line: { color: C.accentMint, width: 0 } });
    sl.addText(text, { x: 5.45, y: 1.93 + i * 0.76, w: 4.0, h: 0.6, fontSize: 10, fontFace: FONT_B, color: C.offWhite, margin: 0, valign: 'middle' });
  });

  // Bottom insight
  sl.addShape(pres.shapes.RECTANGLE, { x: 0.4, y: 5.4, w: 9.2, h: 0.7,
    fill: { color: C.accentBlue, transparency: 80 }, line: { color: C.accentCyan, width: 0.5, transparency: 50 } });
  sl.addText('La integración IoT-Smart Grid debe reencuadrarse como amenaza sistémica ciberfísica', {
    x: 0.6, y: 5.45, w: 8.8, h: 0.6, fontSize: 11, fontFace: FONT_B, color: C.white, italic: true, align: 'center', valign: 'middle', margin: 0
  });
  footerDark(sl);
}

// ── SLIDE 4: METODOLOGÍA ─────────────────────────────────────
{
  const sl = pres.addSlide();
  lightSlide(sl);
  accentBar(sl, C.accentBlue, 0.1, 0);
  sectionTag(sl, 'METODOLOGÍA', 0.5, 0.2, C.accentBlue);
  lightTitle(sl, 'Revisión Sistemática PRISMA', 0.55);

  // PRISMA flow
  const steps = [
    { label: 'Registros Iniciales', n: '2.318', color: C.accentBlue },
    { label: 'Duplicados Eliminados', n: '−847', color: C.bodyText },
    { label: 'Eliminados por Título', n: '−1.056', color: C.bodyText },
    { label: 'Estudios Incluidos', n: '215', color: C.accentMint },
  ];

  steps.forEach((s, i) => {
    const x = 0.6 + i * 2.25;
    const isFirst = i === 0, isLast = i === 3;
    sl.addShape(pres.shapes.RECTANGLE, {
      x, y: 1.5, w: 2.0, h: 3.5,
      fill: { color: isFirst || isLast ? s.color : C.white, transparency: isFirst || isLast ? 10 : 0 },
      line: { color: s.color, width: 1.5 },
      shadow: { type: 'outer', color: '000000', blur: 6, offset: 2, angle: 135, opacity: 0.12 }
    });
    sl.addText(s.n, {
      x, y: 1.9, w: 2.0, h: 1.2,
      fontSize: 32, fontFace: FONT_H, color: isFirst || isLast ? C.white : s.color,
      bold: true, align: 'center', valign: 'middle', margin: 0
    });
    sl.addText(s.label, {
      x, y: 3.3, w: 2.0, h: 1.0,
      fontSize: 11, fontFace: FONT_B, color: isFirst || isLast ? C.white : C.darkText,
      align: 'center', valign: 'middle', margin: 5
    });
    // Arrow
    if (i < 3) {
      sl.addShape(pres.shapes.LINE, {
        x: x + 2.02, y: 3.25, w: 0.2, h: 0,
        line: { color: C.accentBlue, width: 2 }
      });
    }
  });

  // Protocol note
  sl.addShape(pres.shapes.RECTANGLE, { x: 0.5, y: 5.25, w: 9.0, h: 0.8,
    fill: { color: C.accentBlue, transparency: 85 }, line: { color: C.accentBlue, width: 0.5, transparency: 40 } });
  sl.addText('El protocolo PRISMA garantiza trazabilidad y replicabilidad del proceso de selección. La legitimidad científica del estudio se fundamenta en este método sistemático de revisión.', {
    x: 0.7, y: 5.3, w: 8.6, h: 0.7, fontSize: 10, fontFace: FONT_B, color: C.darkText, align: 'center', valign: 'middle', margin: 0
  });
  footerLight(sl);
}

// ── SLIDE 5: TAXONOMÍA DE AMENAZAS ───────────────────────────
{
  const sl = pres.addSlide();
  darkSlide(sl);
  sectionTag(sl, 'TAXONOMÍA');
  darkTitle(sl, 'Matriz de Amenazas: Impacto × Probabilidad', 0.5);
  accentBar(sl, C.accentCyan, 0.05, 1.22);

  const headers = ['Amenaza', 'Impacto', 'Probabilidad', 'Prioridad', 'Componentes'];
  const rows = [
    ['FDI (False Data Injection)', 'Catastrófico', 'Media', 'MUY ALTA', 'Estimación estado, relés'],
    ['Ransomware', 'Alto', 'Alta', 'MUY ALTA', 'SCADA, HMI, datos'],
    ['DoS Coordinado', 'Alto', 'Media', 'MUY ALTA', 'Red, control'],
    ['Ataques a Mercado Eléctrico', 'Alto', 'Baja', 'ALTA', 'Precios nodales'],
    ['Manipulación de Medidores', 'Medio', 'Alta', 'ALTA', 'Facturación, consumo'],
    ['Ataques a V2G/EV', 'Alto', 'Media', 'ALTA', 'Cargadores, frecuencia'],
    ['Jamming Protocolos ISM', 'Medio', 'Media', 'MEDIA', 'ZigBee/Wi-Fi'],
    ['Inyección de Malware', 'Alto', 'Media', 'MUY ALTA', 'Firmware, control'],
  ];

  const priColors = { 'MUY ALTA': C.accentAmber, 'ALTA': C.accentCyan, 'MEDIA': C.accentMint };
  const colW = [2.5, 1.2, 1.3, 1.2, 3.4];
  const colX = [0.35, 2.85, 4.05, 5.35, 6.55];
  const rowH = 0.55;
  const startY = 1.3;

  // Header
  headers.forEach((h, ci) => {
    sl.addShape(pres.shapes.RECTANGLE, { x: colX[ci], y: startY, w: colW[ci], h: 0.4, fill: { color: C.accentBlue }, line: { color: C.accentBlue, width: 0 } });
    sl.addText(h, { x: colX[ci], y: startY, w: colW[ci], h: 0.4, fontSize: 9, fontFace: FONT_H, color: C.white, bold: true, align: 'center', valign: 'middle', margin: 2 });
  });
  rows.forEach((row, ri) => {
    const y = startY + 0.42 + ri * rowH;
    const bg = ri % 2 === 0 ? C.midBg : C.cardBg;
    sl.addShape(pres.shapes.RECTANGLE, { x: 0.35, y, w: 9.3, h: rowH - 0.04, fill: { color: bg }, line: { color: '00000000', width: 0 } });
    row.forEach((cell, ci) => {
      if (ci === 3) {
        const pc = priColors[cell] || C.lightGray;
        sl.addShape(pres.shapes.RECTANGLE, { x: colX[ci] + 0.05, y: y + 0.1, w: colW[ci] - 0.1, h: rowH - 0.24, fill: { color: pc, transparency: 70 }, line: { color: pc, width: 0.5 } });
        sl.addText(cell, { x: colX[ci], y, w: colW[ci], h: rowH - 0.04, fontSize: 8, fontFace: FONT_H, color: pc, bold: true, align: 'center', valign: 'middle', margin: 0 });
      } else {
        sl.addText(cell, { x: colX[ci] + 0.05, y, w: colW[ci] - 0.1, h: rowH - 0.04, fontSize: ci === 0 ? 9 : 8, fontFace: FONT_B, color: C.offWhite, align: ci === 0 ? 'left' : 'center', valign: 'middle', margin: 0 });
      }
    });
  });

  sl.addText('Los niveles son asignados mediante consenso literario de expertos, no datos empíricos de frecuencia de incidentes reales.', {
    x: 0.35, y: 6.95, w: 9.3, h: 0.25, fontSize: 7.5, fontFace: FONT_B, color: C.lightGray, italic: true, align: 'center', margin: 0
  });
  footerDark(sl);
}

// ── SLIDE 6: AUTENTICACIÓN Y PRIVACIDAD ──────────────────────
{
  const sl = pres.addSlide();
  darkSlide(sl);
  sectionTag(sl, 'AUTENTICACIÓN');
  darkTitle(sl, 'Autenticación y Privacidad: Soluciones IoT', 0.5);
  accentBar(sl, C.accentMint, 0.05, 1.22);

  // Left: Arquitecturas
  darkCard(sl, 0.4, 1.35, 4.5, 4.0);
  sl.addText('ARQUITECTURAS DE AUTENTICACIÓN', { x: 0.55, y: 1.45, w: 4.2, h: 0.35, fontSize: 10, fontFace: FONT_H, color: C.accentCyan, bold: true, margin: 0 });

  const archs = [
    { title: 'CENTRALIZADA (PKI)', color: C.accentBlue, items: ['Autoridad Certificadora (CA)', 'Gestión de certificados X.509', 'Escalabilidad limitada', '⚠ Punto único de fallo'] },
    { title: 'DESCENTRALIZADA (Blockchain / PUF)', color: C.accentMint, items: ['Blockchain: Registro inmutable', 'PUF: IDs basados en propiedades físicas', 'Mayor resiliencia', '⚠ Baja tx/seg para redes AMI'] },
  ];
  archs.forEach((a, i) => {
    const y = 1.9 + i * 1.95;
    sl.addShape(pres.shapes.RECTANGLE, { x: 0.55, y, w: 4.2, h: 1.75, fill: { color: C.midBg }, line: { color: a.color, width: 0.7, transparency: 30 } });
    sl.addShape(pres.shapes.RECTANGLE, { x: 0.55, y, w: 4.2, h: 0.32, fill: { color: a.color, transparency: 20 }, line: { color: a.color, width: 0 } });
    sl.addText(a.title, { x: 0.65, y, w: 4.0, h: 0.32, fontSize: 9, fontFace: FONT_H, color: C.white, bold: true, valign: 'middle', margin: 0 });
    a.items.forEach((item, j) => {
      sl.addText(item, { x: 0.75, y: y + 0.38 + j * 0.33, w: 3.9, h: 0.3, fontSize: 9, fontFace: FONT_B, color: item.startsWith('⚠') ? C.accentAmber : C.offWhite, margin: 0 });
    });
  });

  // Right: Criptografía
  darkCard(sl, 5.1, 1.35, 4.5, 4.0);
  sl.addText('CRIPTOGRAFÍA LIGERA PARA IoT', { x: 5.25, y: 1.45, w: 4.2, h: 0.35, fontSize: 10, fontFace: FONT_H, color: C.accentMint, bold: true, margin: 0 });

  const cryptoItems = [
    { alg: 'XOR', note: '900× más rápido que RSA', bar: 100, color: C.accentMint },
    { alg: 'ECC-256', note: '= seguridad de RSA 3.072 bits', bar: 75, color: C.accentCyan },
    { alg: 'RSA-3072', note: 'Alto costo computacional', bar: 20, color: C.accentAmber },
  ];
  cryptoItems.forEach((c, i) => {
    const y = 1.9 + i * 1.0;
    sl.addShape(pres.shapes.RECTANGLE, { x: 5.25, y, w: 4.2, h: 0.85, fill: { color: C.midBg }, line: { color: c.color, width: 0.4, transparency: 50 } });
    sl.addText(c.alg, { x: 5.35, y: y + 0.06, w: 1.5, h: 0.3, fontSize: 13, fontFace: FONT_H, color: c.color, bold: true, margin: 0 });
